package main.rice.parse;

import main.rice.node.APyNode;
import java.util.List;

/**
 * A data class for representing a parsed configuration file.
 */
public class ConfigFile {

    /**
     * The name of the function to be tested.
     */
    private String funcName;

    /**
     * The number of random test cases to generate.
     */
    private int numRand;

    /**
     * The list of PyNodes representing the function's arguments.
     */
    private List<APyNode<?>> nodes;

    /**
     * Constructor for a ConfigFile.
     *
     * @param funcName the name of the function to be tested
     * @param numRand  the number of random test cases to generate
     * @param nodes    the list of PyNodes representing the function's arguments
     */
    public ConfigFile(String funcName, int numRand, List<APyNode<?>> nodes) {
        this.funcName = funcName;
        this.numRand = numRand;
        this.nodes = nodes;
    }

    /**
     * Returns the name of the function to be tested.
     *
     * @return the function name
     */
    public String getFuncName() {
        return this.funcName;
    }

    /**
     * Returns the number of random test cases to generate.
     *
     * @return the number of random tests
     */
    public int getNumRand() {
        return this.numRand;
    }

    /**
     * Returns the list of PyNodes representing the function's arguments.
     *
     * @return the list of PyNodes
     */
    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }
}

