package main.rice.parse;

import main.rice.node.*;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

import java.util.*;

/**
 * A parser for configuration files.
 */
public class ConfigFileParser {

    /**
     * Parses a configuration file from a JSON string.
     *
     * @param content the JSON string to parse
     * @return a ConfigFile object representing the parsed configuration
     * @throws InvalidConfigException if the configuration is invalid
     */
    public ConfigFile parse(String content) throws InvalidConfigException {
        JSONObject obj;
        try {
            obj = new JSONObject(content);
        } catch (JSONException e) {
            throw new InvalidConfigException("Invalid JSON format");
        }

        // Validate required fields
        String[] requiredFields = {"fname", "types", "exhaustive domain", "random domain", "num random"};
        for (String field : requiredFields) {
            if (!obj.has(field)) {
                throw new InvalidConfigException("Missing required field: " + field);
            }
        }

        // Validate field types
        if (!(obj.get("fname") instanceof String)) {
            throw new InvalidConfigException("fname must be a string");
        }
        if (!(obj.get("types") instanceof JSONArray)) {
            throw new InvalidConfigException("types must be an array");
        }
        if (!(obj.get("exhaustive domain") instanceof JSONArray)) {
            throw new InvalidConfigException("exhaustive domain must be an array");
        }
        if (!(obj.get("random domain") instanceof JSONArray)) {
            throw new InvalidConfigException("random domain must be an array");
        }
        if (!(obj.get("num random") instanceof Integer)) {
            throw new InvalidConfigException("num random must be an integer");
        }

        String fname = obj.getString("fname");
        JSONArray typesArr = obj.getJSONArray("types");
        JSONArray exDomArr = obj.getJSONArray("exhaustive domain");
        JSONArray ranDomArr = obj.getJSONArray("random domain");
        int numRand = obj.getInt("num random");

        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative");
        }

        if (typesArr.length() != exDomArr.length() || typesArr.length() != ranDomArr.length()) {
            throw new InvalidConfigException("Array lengths for types and domains must match");
        }

        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < typesArr.length(); i++) {
            if (!(typesArr.get(i) instanceof String)) {
                throw new InvalidConfigException("Type must be a string");
            }
            if (!(exDomArr.get(i) instanceof String)) {
                throw new InvalidConfigException("Exhaustive domain must be a string");
            }
            if (!(ranDomArr.get(i) instanceof String)) {
                throw new InvalidConfigException("Random domain must be a string");
            }

            String typeStr = typesArr.getString(i);
            String exDomStr = exDomArr.getString(i);
            String ranDomStr = ranDomArr.getString(i);

            nodes.add(parseTypeAndDomain(typeStr, exDomStr, ranDomStr));
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    /**
     * Parses a type string and its corresponding domain strings into a PyNode.
     */
    private APyNode<?> parseTypeAndDomain(String type, String exDom, String ranDom) throws InvalidConfigException {
        if (type.contains(" ")) {
            throw new InvalidConfigException("Type string contains spaces");
        }
        // Split domains by semicolon, but be careful with nested structures if any
        // Based on the format, semicolon seems to be the separator.
        String[] exParts = exDom.split(";");
        String[] ranParts = ranDom.split(";");

        Iterator<String> exIt = Arrays.asList(exParts).iterator();
        Iterator<String> ranIt = Arrays.asList(ranParts).iterator();

        APyNode<?> node = buildNode(type, exIt, ranIt);

        if (exIt.hasNext() || ranIt.hasNext()) {
            throw new InvalidConfigException("Too many domain parts for type: " + type);
        }

        return node;
    }

    /**
     * Recursively builds a PyNode from type and domain parts.
     */
    private APyNode<?> buildNode(String type, Iterator<String> exIt, Iterator<String> ranIt) throws InvalidConfigException {
        if (!exIt.hasNext() || !ranIt.hasNext()) {
            throw new InvalidConfigException("Insufficient domain parts for type: " + type);
        }

        if (type.equals("int")) {
            PyIntNode node = new PyIntNode();
            node.setExDomain(parseRange(exIt.next()));
            node.setRanDomain(parseRange(ranIt.next()));
            return node;
        } else if (type.equals("bool")) {
            PyBoolNode node = new PyBoolNode();
            node.setExDomain(parseRange(exIt.next()));
            node.setRanDomain(parseRange(ranIt.next()));
            return node;
        } else if (type.equals("float")) {
            PyFloatNode node = new PyFloatNode();
            node.setExDomain(parseRange(exIt.next()));
            node.setRanDomain(parseRange(ranIt.next()));
            return node;
        } else if (type.equals("str")) {
            List<Integer> exLen = parseRange(exIt.next());
            List<Integer> ranLen = parseRange(ranIt.next());
            if (!exIt.hasNext() || !ranIt.hasNext()) {
                throw new InvalidConfigException("Missing character domain for str");
            }
            String exChars = exIt.next();
            String ranChars = ranIt.next();
            // Character domain validation? Spurious characters etc?
            // "No spurious parentheses or spaces"
            if (exChars.contains(" ") || exChars.contains("(") || exChars.contains(")") ||
                ranChars.contains(" ") || ranChars.contains("(") || ranChars.contains(")")) {
                throw new InvalidConfigException("Spurious characters in character domain");
            }
            PyStringNode node = new PyStringNode(exChars);
            node.setExDomain(exLen);
            node.setRanDomain(ranLen);
            return node;
        } else if (type.startsWith("list(")) {
            String inner = getInner(type, "list(");
            List<Integer> exLen = parseRange(exIt.next());
            List<Integer> ranLen = parseRange(ranIt.next());
            APyNode<?> child = buildNode(inner, exIt, ranIt);
            PyListNode<?> node = new PyListNode<>(child);
            node.setExDomain(exLen);
            node.setRanDomain(ranLen);
            return node;
        } else if (type.startsWith("set(")) {
            String inner = getInner(type, "set(");
            List<Integer> exLen = parseRange(exIt.next());
            List<Integer> ranLen = parseRange(ranIt.next());
            APyNode<?> child = buildNode(inner, exIt, ranIt);
            PySetNode<?> node = new PySetNode<>(child);
            node.setExDomain(exLen);
            node.setRanDomain(ranLen);
            return node;
        } else if (type.startsWith("tuple(")) {
            String inner = getInner(type, "tuple(");
            List<Integer> exLen = parseRange(exIt.next());
            List<Integer> ranLen = parseRange(ranIt.next());
            APyNode<?> child = buildNode(inner, exIt, ranIt);
            PyTupleNode<?> node = new PyTupleNode<>(child);
            node.setExDomain(exLen);
            node.setRanDomain(ranLen);
            return node;
        } else if (type.startsWith("dict(")) {
            String inner = getInner(type, "dict(");
            List<Integer> exSize = parseRange(exIt.next());
            List<Integer> ranSize = parseRange(ranIt.next());
            int colonIdx = findColon(inner);
            String keyType = inner.substring(0, colonIdx);
            String valType = inner.substring(colonIdx + 1);
            APyNode<?> keyChild = buildNode(keyType, exIt, ranIt);
            APyNode<?> valChild = buildNode(valType, exIt, ranIt);
            PyDictNode<?, ?> node = new PyDictNode<>(keyChild, valChild);
            node.setExDomain(exSize);
            node.setRanDomain(ranSize);
            return node;
        } else {
            throw new InvalidConfigException("Unknown type: " + type);
        }
    }

    /**
     * Extracts the inner type from a parameterized type string.
     */
    private String getInner(String type, String prefix) throws InvalidConfigException {
        if (!type.endsWith(")")) {
            throw new InvalidConfigException("Missing closing parenthesis in type: " + type);
        }
        return type.substring(prefix.length(), type.length() - 1);
    }

    /**
     * Finds the colon that separates key and value types in a dict type string.
     */
    private int findColon(String s) throws InvalidConfigException {
        int depth = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '(') depth++;
            else if (c == ')') depth--;
            else if (c == ':' && depth == 0) return i;
        }
        throw new InvalidConfigException("Colon not found at depth 0 in: " + s);
    }

    /**
     * Parses a range string into a list of integers.
     */
    private List<Integer> parseRange(String range) throws InvalidConfigException {
        if (range.contains(" ") || range.contains("(") || range.contains(")")) {
            throw new InvalidConfigException("Spurious characters in range: " + range);
        }
        if (range.startsWith("[") && range.endsWith("]")) {
            String content = range.substring(1, range.length() - 1);
            if (content.isEmpty()) return new ArrayList<>();
            String[] parts = content.split(",");
            List<Integer> res = new ArrayList<>();
            for (String p : parts) {
                try {
                    res.add(Integer.parseInt(p));
                } catch (NumberFormatException e) {
                    throw new InvalidConfigException("Invalid number in range: " + p);
                }
            }
            return res;
        } else if (range.contains("~")) {
            String[] parts = range.split("~");
            if (parts.length != 2) {
                throw new InvalidConfigException("Invalid range format: " + range);
            }
            try {
                int low = Integer.parseInt(parts[0]);
                int high = Integer.parseInt(parts[1]);
                if (low > high) {
                    throw new InvalidConfigException("Invalid range (low > high): " + range);
                }
                List<Integer> res = new ArrayList<>();
                for (int i = low; i <= high; i++) {
                    res.add(i);
                }
                return res;
            } catch (NumberFormatException e) {
                throw new InvalidConfigException("Invalid number in range: " + range);
            }
        } else {
            try {
                int val = Integer.parseInt(range);
                return Collections.singletonList(val);
            } catch (NumberFormatException e) {
                throw new InvalidConfigException("Invalid range: " + range);
            }
        }
    }
}

package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Set;

/**
 * The main entry point for the test generation and selection system.
 */
public class Main {

    /**
     * Entry point for the program. Parses arguments, generates tests, runs tests,
     * and outputs the concise set of test cases.
     *
     * @param args the command-line arguments: configPath, solutionPath, implDirPath
     */
    public static void main(String[] args) {
        if (args.length < 3) {
            System.err.println("Usage: Main <configPath> <solutionPath> <implDirPath>");
            return;
        }

        try {
            Set<TestCase> conciseSet = generateTests(args);
            for (TestCase testCase : conciseSet) {
                System.out.println(testCase);
            }
        } catch (InvalidConfigException | IOException | InterruptedException e) {
            // Error occurred, but just return for now
        }
    }

    /**
     * Generates a concise set of test cases based on the given configuration,
     * reference solution, and directory of implementations.
     *
     * @param args the arguments: configPath, solutionPath, implDirPath
     * @return the concise set of test cases
     * @throws InvalidConfigException if the configuration is invalid
     * @throws IOException            if any file operations fail
     * @throws InterruptedException   if the testing process is interrupted
     */
    public static Set<TestCase> generateTests(String[] args)
            throws InvalidConfigException, IOException, InterruptedException {
        String configPath = args[0];
        String solutionPath = args[1];
        String implDirPath = args[2];

        // 1. Read and parse the configuration file
        String configContent = Files.readString(Path.of(configPath));
        ConfigFileParser parser = new ConfigFileParser();
        ConfigFile configFile = parser.parse(configContent);

        // 2. Generate the base set of test cases
        BaseSetGenerator baseGen = new BaseSetGenerator(configFile.getNodes(),
                configFile.getNumRand());
        List<TestCase> baseSet = baseGen.genBaseSet();

        // 3. Run the test suite on the reference solution and buggy implementations
        Tester tester = new Tester(configFile.getFuncName(), solutionPath,
                implDirPath, baseSet);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        // 4. Find the approximately minimal set of test cases that catches all bugs
        return ConciseSetGenerator.setCover(results);
    }
}

package test.rice.parse;

import main.rice.node.*;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

class ConfigFileParserAgentTest {

    private ConfigFileParser parser;

    @BeforeEach
    void setUp() {
        parser = new ConfigFileParser();
    }

    @Test
    void testParseInt() throws InvalidConfigException {
        String json = """
            {
                "fname": "testFunc",
                "types": ["int"],
                "exhaustive domain": ["1~3"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        ConfigFile cf = parser.parse(json);
        assertEquals("testFunc", cf.getFuncName());
        assertEquals(10, cf.getNumRand());
        assertEquals(1, cf.getNodes().size());
        assertTrue(cf.getNodes().get(0) instanceof PyIntNode);
        assertEquals(Arrays.asList(1, 2, 3), cf.getNodes().get(0).getExDomain());
        assertEquals(Arrays.asList(1, 2, 3, 4, 5), cf.getNodes().get(0).getRanDomain());
    }

    @Test
    void testParseBool() throws InvalidConfigException {
        String json = """
            {
                "fname": "testBool",
                "types": ["bool"],
                "exhaustive domain": ["0~1"],
                "random domain": ["1"],
                "num random": 5
            }
            """;
        ConfigFile cf = parser.parse(json);
        assertTrue(cf.getNodes().get(0) instanceof PyBoolNode);
        assertEquals(Arrays.asList(0, 1), cf.getNodes().get(0).getExDomain());
        assertEquals(Collections.singletonList(1), cf.getNodes().get(0).getRanDomain());
    }

    @Test
    void testParseFloat() throws InvalidConfigException {
        String json = """
            {
                "fname": "testFloat",
                "types": ["float"],
                "exhaustive domain": ["1~2"],
                "random domain": ["[3,4]"],
                "num random": 0
            }
            """;
        ConfigFile cf = parser.parse(json);
        assertTrue(cf.getNodes().get(0) instanceof PyFloatNode);
        assertEquals(Arrays.asList(1, 2), cf.getNodes().get(0).getExDomain());
        assertEquals(Arrays.asList(3, 4), cf.getNodes().get(0).getRanDomain());
    }

    @Test
    void testParseStr() throws InvalidConfigException {
        String json = """
            {
                "fname": "testStr",
                "types": ["str"],
                "exhaustive domain": ["0~2;abc"],
                "random domain": ["1~3;xyz"],
                "num random": 10
            }
            """;
        ConfigFile cf = parser.parse(json);
        assertTrue(cf.getNodes().get(0) instanceof PyStringNode);
        assertEquals(Arrays.asList(0, 1, 2), cf.getNodes().get(0).getExDomain());
        assertEquals(Arrays.asList(1, 2, 3), cf.getNodes().get(0).getRanDomain());
        // Note: PyStringNode.charDomain is private and final, can't easily check it
        // but we can trust the constructor was called with "abc".
    }

    @Test
    void testParseList() throws InvalidConfigException {
        String json = """
            {
                "fname": "testList",
                "types": ["list(int)"],
                "exhaustive domain": ["0~1;1~2"],
                "random domain": ["0~2;1~3"],
                "num random": 10
            }
            """;
        ConfigFile cf = parser.parse(json);
        assertTrue(cf.getNodes().get(0) instanceof PyListNode);
        assertEquals(Arrays.asList(0, 1), cf.getNodes().get(0).getExDomain());
        APyNode<?> child = cf.getNodes().get(0).getLeftChild();
        assertTrue(child instanceof PyIntNode);
        assertEquals(Arrays.asList(1, 2), child.getExDomain());
    }

    @Test
    void testParseDict() throws InvalidConfigException {
        String json = """
            {
                "fname": "testDict",
                "types": ["dict(int:str)"],
                "exhaustive domain": ["1~1;2~2;0~1;ab"],
                "random domain": ["1~1;3~3;0~2;xy"],
                "num random": 10
            }
            """;
        // dict domain parts:
        // 1. size range: 1~1
        // 2. key (int) range: 2~2
        // 3. val (str) length range: 0~1
        // 4. val (str) char domain: ab
        ConfigFile cf = parser.parse(json);
        assertTrue(cf.getNodes().get(0) instanceof PyDictNode);
        assertEquals(Collections.singletonList(1), cf.getNodes().get(0).getExDomain());

        PyDictNode<?, ?> dictNode = (PyDictNode<?, ?>) cf.getNodes().get(0);
        assertTrue(dictNode.getLeftChild() instanceof PyIntNode);
        assertTrue(dictNode.getRightChild() instanceof PyStringNode);

        assertEquals(Collections.singletonList(2), dictNode.getLeftChild().getExDomain());
        assertEquals(Arrays.asList(0, 1), dictNode.getRightChild().getExDomain());
    }

    @Test
    void testParseNested() throws InvalidConfigException {
        String json = """
            {
                "fname": "testNested",
                "types": ["list(list(int))"],
                "exhaustive domain": ["1~1;1~1;1~2"],
                "random domain": ["1~1;1~1;1~3"],
                "num random": 10
            }
            """;
        ConfigFile cf = parser.parse(json);
        APyNode<?> outerList = cf.getNodes().get(0);
        assertTrue(outerList instanceof PyListNode);
        APyNode<?> innerList = outerList.getLeftChild();
        assertTrue(innerList instanceof PyListNode);
        APyNode<?> intNode = innerList.getLeftChild();
        assertTrue(intNode instanceof PyIntNode);
        assertEquals(Arrays.asList(1, 2), intNode.getExDomain());
    }

    @Test
    void testMultipleArgs() throws InvalidConfigException {
        String json = """
            {
                "fname": "testMulti",
                "types": ["int", "bool"],
                "exhaustive domain": ["1~2", "0~1"],
                "random domain": ["1~3", "1~1"],
                "num random": 10
            }
            """;
        ConfigFile cf = parser.parse(json);
        assertEquals(2, cf.getNodes().size());
        assertTrue(cf.getNodes().get(0) instanceof PyIntNode);
        assertTrue(cf.getNodes().get(1) instanceof PyBoolNode);
    }

    @Test
    void testInvalidRangeFormat() {
        String json = """
            {
                "fname": "testErr",
                "types": ["int"],
                "exhaustive domain": ["1-3"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }

    @Test
    void testLowGreaterThanHigh() {
        String json = """
            {
                "fname": "testErr",
                "types": ["int"],
                "exhaustive domain": ["3~1"],
                "random domain": ["1~5"],
                "num random": 10
            }
            """;
        assertThrows(InvalidConfigException.class, () -> parser.parse(json));
    }
}
